const msg = $input.first().json;

// Superchat Trigger Struktur
const messageId = msg.message?.id || null;
const conversationId = msg.message?.conversation_id || null;

// Email Content
const content = msg.message?.content || {};
const subject = content.subject || '';
const textBody = content.text || content.html?.replace(/<[^>]*>/g, ' ').substring(0, 1500) || '';

// From Address
const fromAddress = (msg.message?.from?.identifier || '').toLowerCase();

// Extract domain
const domain = fromAddress.includes('@') ? fromAddress.split('@')[1] : '';

// Attachments - liegt in content.files
const files = content.files || [];
const fileIds = files.map(f => f.id).filter(Boolean);

// Known spam domains
const SPAM_DOMAINS = [
  'linkedin.com',
  'onepage.io',
  'mobbin.com',
  'skool.com',
  'auftrag.jetzt',
  'primus-personal.de',
  'email.contorion.de',
  'baumarkt.toom.de',
  'xing.com',
  'newsletter.',
  'marketing.',
  'noreply@'
];

const isSpam = SPAM_DOMAINS.some(spam => 
  domain.endsWith(spam) || 
  domain.includes(spam) ||
  fromAddress.includes(spam)
);

// MagicPlan detection
const isMagicPlan = domain === 'magicplan.app' || 
                    subject.toLowerCase().includes('magicplan') ||
                    fromAddress.includes('magicplan');

return {
  json: {
    superchat_message_id: messageId,
    superchat_conversation_id: conversationId,
    from_address: fromAddress,
    domain: domain,
    subject: subject,
    body_preview: textBody.substring(0, 1500),
    file_ids: fileIds,
    has_attachments: fileIds.length > 0,
    is_spam: isSpam,
    is_magicplan: isMagicPlan
  }
};

