const input = $input.first().json;
const metadata = $('📋 Extract Metadata').first().json;
const supplier = $('🏢 Supplier Lookup').first().json;

// Claude Response parsen
let parsed;
try {
  // Claude gibt manchmal markdown zurück
  const text = input.message?.content || input.content?.[0]?.text || '';
  const jsonMatch = text.match(/\{[\s\S]*?\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : { doc_type: 'OTHER', confidence: 0.5, reason: 'Parse failed' };
} catch (e) {
  parsed = { doc_type: 'OTHER', confidence: 0.5, reason: 'JSON parse error: ' + e.message };
}

// Event-würdig?
const EVENT_TYPES = ['INVOICE_IN', 'PROJECT_ORDER', 'CREDIT_NOTE', 'REMINDER', 'MAGICPLAN', 'BID_REQUEST'];
const needsEvent = EVENT_TYPES.includes(parsed.doc_type) && parsed.confidence >= 0.7;

return {
  json: {
    ...metadata,
    ...parsed,
    supplier_id: supplier.supplier_id || null,
    supplier_name: supplier.supplier_name || null,
    needs_event: needsEvent
  }
};

